ass="btnbtn-outline-secondary"onclick="refreshDashboard()"><iclass="fasfa-sync-altme-2"></i>Refresh</button></div></div><!--KeyMetricsRow--><divclass="rowmb-4"><divclass="col-md-3mb-3"><divclass="card"><divclass="d-flexjustify-content-betweenalign-items-center"><div><h6class="text-mutedmb-2">TotalPersonil</h6><h3class="mb-0"id="metricTotalPersonil">0</h3><smallclass="text-success"><iclass="fasfa-arrow-up"></i>Aktif</small></div><divclass="stat-icon"style="background:linear-gradient(135deg,#1a237e,#3949ab);"><iclass="fasfa-users"></i></div></div></div></div><divclass="col-md-3mb-3"><divclass="card"><divclass="d-flexjustify-content-betweenalign-items-center"><div><h6class="text-mutedmb-2">JabatanTerisi</h6><h3class="mb-0"id="metricJabatanTerisi">0</h3><smallclass="text-muted">dari<spanid="metricTotalJabatan">0</span>jabatan</small></div><divclass="stat-icon"style="background:linear-gradient(135deg,#198754,#28a745);"><iclass="fasfa-briefcase"></i></div></div></div></div><divclass="col-md-3mb-3"><divclass="card"><divclass="d-flexjustify-content-betweenalign-items-center"><div><h6class="text-mutedmb-2">PenugasanAktif</h6><h3class="mb-0"id="metricPenugasanAktif">0</h3><smallclass="text-warning">Sementara</small></div><divclass="stat-icon"style="background:linear-gradient(135deg,#fd7e14,#ffc107);"><iclass="fasfa-user-clock"></i></div></div></div></div><divclass="col-md-3mb-3"><divclass="card"><divclass="d-flexjustify-content-betweenalign-items-center"><div><h6class="text-mutedmb-2">Compliance</h6><h3class="mb-0"id="metricCompliance">0%</h3><divid="complianceStatus"></div></div><divclass="stat-icon"style="background:linear-gradient(135deg,#dc3545,#f44);"><iclass="fasfa-shield-alt"></i></div></div></div></div></div><!--ChartsRow--><divclass="rowmb-4"><divclass="col-md-6mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-chart-pieme-2"></i>DistribusiPersonilperUnsur</h5><divclass="chart-container"><canvasid="unsurChart"></canvas></div></div></div><divclass="col-md-6mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-chart-barme-2"></i>DistribusiperPangkat</h5><divclass="chart-container"><canvasid="pangkatChart"></canvas></div></div></div></div><!--ComplianceandAlertsRow--><divclass="rowmb-4"><divclass="col-md-6mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-exclamation-triangleme-2"></i>StatusCompliance</h5><divid="complianceDetails"><!--Compliancedetailswillbeloadedhere--></div></div></div><divclass="col-md-6mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-bellme-2"></i>Peringatan&Notifikasi</h5><divid="alertsContainer"><!--Alertswillbeloadedhere--></div></div></div></div><!--QuickLinksandRecentActivity--><divclass="row"><divclass="col-md-4mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-linkme-2"></i>QuickLinks</h5><divclass="list-grouplist-group-flush"><ahref="personil_management_v2.php"class="list-group-itemlist-group-item-actionquick-link"><iclass="fasfa-usersme-2text-primary"></i>PersonilManagement<iclass="fasfa-chevron-rightfloat-endmt-1"></i></a><ahref="kepegawaian_management_v2.php"class="list-group-itemlist-group-item-actionquick-link"><iclass="fasfa-user-tieme-2text-success"></i>Kepegawaian<iclass="fasfa-chevron-rightfloat-endmt-1"></i></a><ahref="penugasan_management_v2.php"class="list-group-itemlist-group-item-actionquick-link"><iclass="fasfa-briefcaseme-2text-warning"></i>Penugasan<iclass="fasfa-chevron-rightfloat-endmt-1"></i></a></div></div></div><divclass="col-md-8mb-3"><divclass="card"><h5class="mb-3"><iclass="fasfa-historyme-2"></i>AktivitasTerbaru</h5><divclass="recent-activity"id="recentActivity"><!--Activitywillbeloadedhere--></div></div></div></div></main></div></div><scriptsrc="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/js/bootstrap.bundle.min.js"></script><scriptsrc="https://cdn.jsdelivr.net/npm/chart.js"></script><script>letunsurChart,pangkatChart;document.addEventListener('DOMContentLoaded',function(){loadDashboardData();});functionrefreshDashboard(){loadDashboardData();}functionloadDashboardData(){loadPersonilStatistics();loadKepegawaianStatistics();loadPenugasanStatistics();loadComplianceStatus();}functionloadPersonilStatistics(){constformData=newFormData();formData.append('action','get_personil_statistics');fetch(api_url('personil_management_v2.php'),{method:'POST',body:formData}).then(response=>response.json()).then(data=>{if(data.success){document.getElementById('metricTotalPersonil').textContent=data.data.total.aktif||0;/RenderUnsurChartrenderUnsurChart(data.data.by_unsur);/RenderPangkatChartrenderPangkatChart(data.data.by_pangkat);}}).catch(error=>console.error('Error:',error));}functionloadKepegawaianStatistics(){constformData=newFormData();formData.append('action','get_kepegawaian_statistics');fetch(api_url('kepegawaian_management_v2.php'),{method:'POST',body:formData}).then(response=>response.json()).then(data=>{if(data.success){constjabatanKosong=data.data.jabatan_kosong.empty_positions||0;constjabatanTerisi=98-jabatanKosong;/Total98jabatandocument.getElementById('metricJabatanTerisi').textContent=jabatanTerisi;document.getElementById('metricTotalJabatan').textContent=98;}}).catch(error=>console.error('Error:',error));}functionloadPenugasanStatistics(){constformData=newFormData();formData.append('action','get_penugasan_statistics');fetch(api_url('penugasan_management_v2.php'),{method:'POST',body:formData}).then(response=>response.json()).then(data=>{if(data.success){consttotal=data.data.by_type.reduce((sum,item)=>sum+parseInt(item.count),0);document.getElementById('metricPenugasanAktif').textContent=total;/CalculateoverallcomplianceconstpsPercentage=parseFloat(data.data.ps_compliance.percentage);constcompliance=psPercentage<=15?100:Math.max(0,100-((psPercentage-15)*2));document.getElementById('metricCompliance').textContent=compliance.toFixed(1)+'%';conststatusDiv=document.getElementById('complianceStatus');if(compliance>=90){statusDiv.innerHTML='<spanclass="badgebg-success">Excellent</span>';}elseif(compliance>=70){statusDiv.innerHTML='<spanclass="badgebg-warning">Good</span>';}else{statusDiv.innerHTML='<spanclass="badgebg-danger">NeedsAttention</span>';}/RendercompliancedetailsrenderComplianceDetails(data.data);/RenderalertsrenderAlerts(data.data);}}).catch(error=>console.error('Error:',error));}functionloadComplianceStatus(){/Thiswouldloaddetailedcompliancestatus/Fornow,we'llusemockdatarenderRecentActivity();}functionrenderUnsurChart(unsurData){constctx=document.getElementById('unsurChart').getContext('2d');if(unsurChart)unsurChart.destroy();constlabels=unsurData.map(item=>item.nama_unsur.replace('UNSUR',''));constdata=unsurData.map(item=>item.count);constcolors=['#1a237e','#3949ab','#1976d2','#2196f3','#64b5f6','#90caf9'];unsurChart=newChart(ctx,{type:'doughnut',data:{labels:labels,datasets:[{data:data,backgroundColor:colors,borderWidth:2,borderColor:'#fff'}]},options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{position:'bottom',labels:{boxWidth:12,padding:15}}}}});}functionrenderPangkatChart(pangkatData){constctx=document.getElementById('pangkatChart').getContext('2d');if(pangkatChart)pangkatChart.destroy();constlabels=pangkatData.map(item=>item.nama_pangkat);constdata=pangkatData.map(item=>item.count);pangkatChart=newChart(ctx,{type:'bar',data:{labels:labels,datasets:[{label:'JumlahPersonil',data:data,backgroundColor:'#3949ab',borderRadius:5}]},options:{responsive:true,maintainAspectRatio:false,scales:{y:{beginAtZero:true,ticks:{stepSize:1}}},plugins:{legend:{display:false}}}});}functionrenderComplianceDetails(data){constcontainer=document.getElementById('complianceDetails');constpsPercentage=parseFloat(data.ps_compliance.percentage);constisCompliant=psPercentage<=15;container.innerHTML=`<divclass="d-flexjustify-content-betweenalign-items-centermb-3"><span>PSPercentage</span><spanclass="compliance-badge${isCompliant?'compliant':'non-compliant'}">${psPercentage}%${isCompliant?'✓':'✗'}</span></div><divclass="progressmb-3"style="height:10px;"><divclass="progress-bar${isCompliant?'bg-success':'bg-danger'}"role="progressbar"style="width:${Math.min(psPercentage/15*100,100)}%"></div></div><smallclass="text-muted">Maximumallowed:15%</small>`;}functionrenderAlerts(data){constcontainer=document.getElementById('alertsContainer');lethtml='';constexpiring=parseInt(data.expiring_soon.expiring_soon);constexpired=parseInt(data.expired.expired);if(expired>0){html+=`<divclass="alertalert-dangermb-2"><iclass="fasfa-exclamation-circleme-2"></i><strong>${expired}</strong>penugasansudahexpireddanperluditindaklanjuti</div>`;}if(expiring>0){html+=`<divclass="alertalert-warningmb-2"><iclass="fasfa-clockme-2"></i><strong>${expiring}</strong>penugasanakanberakhirdalam7hari</div>`;}constpsPercentage=parseFloat(data.ps_compliance.percentage);if(psPercentage>15){html+=`<divclass="alertalert-dangermb-2"><iclass="fasfa-shield-altme-2"></i><strong>ComplianceWarning!</strong>PSpercentage(${psPercentage}%)melebihibatas15%</div>`;}if(html===''){html='<divclass="alertalert-success"><iclass="fasfa-check-circleme-2"></i>Tidakadaperingatansaatini</div>';}container.innerHTML=html;}functionrenderRecentActivity(){constcontainer=document.getElementById('recentActivity');/ThiswouldloadfromAPI-usingmockdatafornowcontainer.innerHTML=`<divclass="activity-item"><divclass="d-flexjustify-content-between"><strong>KenaikanPangkat</strong><smallclass="text-muted">2jamyanglalu</small></div><pclass="mb-0text-muted">AKPBambangSusantonaikpangkatmenjadiKOMPOL</p></div><divclass="activity-item"><divclass="d-flexjustify-content-between"><strong>MutasiJabatan</strong><smallclass="text-muted">5jamyanglalu</small></div><pclass="mb-0text-muted">IPTUSitiAminahmutasikeSATINTELKAM</p></div><divclass="activity-item"><divclass="d-flexjustify-content-between"><strong>PenugasanBaru</strong><smallclass="text-muted">1hariyanglalu</small></div><pclass="mb-0text-muted">PltKABAGOPSdiassignkeAKPJohnDoe</p></div>`;}</script></body></html>
